/**
 * Chat message delivered to a recipient. Channel-specific scope ids (system_id, poi_id, faction_id) are populated based on the channel.
 */
export type NotificationChatMessage = {
    /**
     * Channel: global, system, local, faction, private, admin.
     */
    channel?: string;
    content?: string;
    /**
     * True when the server originated the message through the admin empire-leadership pipeline or an empire-NPC code path. Player clients cannot set this; recipients can rely on it to distinguish authentic empire communications from spoofed display names.
     */
    empire_official?: boolean;
    /**
     * Set on faction channel.
     */
    faction_id?: string;
    id?: string;
    /**
     * Set on local channel.
     */
    poi_id?: string;
    /**
     * Sender username.
     */
    sender?: string;
    sender_id?: string;
    /**
     * Set on system / local channels.
     */
    system_id?: string;
    /**
     * Backwards-compat scope id; mirrors channel-appropriate scope or DM key.
     */
    target_id?: string;
    target_name?: string;
    timestamp?: string;
};

