/**
 * A player account with progression, customization, and current state.
 */
export type Player = {
    /**
     * Active empire citizenships keyed by empire ID. Independent of the immutable origin empire (player.empire).
     */
    citizenships?: {
        [key: string]: {
            empire_id?: string;
            granted_at?: string;
            /**
             * Source: 'origin', 'auto', 'petition:<id>', or admin/empire-decider name
             */
            granted_by?: string;
        };
    };
    clan_tag?: string;
    created_at?: string;
    credits: number;
    current_poi?: string;
    current_ship_id?: string;
    current_system?: string;
    /**
     * Map of visited system IDs to visit info
     */
    discovered_systems?: {
        [key: string]: unknown;
    };
    /**
     * Last time player sent a distress signal; zero value means never sent
     */
    distress_last_sent_at?: string;
    docked_at_base?: string;
    empire: string;
    experience?: number;
    faction_id?: string;
    faction_rank?: string;
    /**
     * Fleet ID if the player is in a fleet
     */
    fleet_id?: string;
    home_base?: string;
    id: string;
    is_cloaked?: boolean;
    /**
     * Active detention; present only when jailed
     */
    jail?: {
        bounty_owed?: number;
        empire_id?: string;
        jailed_until?: string;
        rep_restoration?: number;
    };
    last_active_at?: string;
    last_chat_check?: string;
    /**
     * Per-channel unread watermarks
     */
    last_chat_check_map?: {
        [key: string]: string;
    };
    /**
     * Last player-initiated command (login, queued mutation, trade). Used to determine online status; not bumped by tick-driven mutations.
     */
    last_command_at?: string;
    last_login_at?: string;
    /**
     * Hex color
     */
    primary_color?: string;
    /**
     * Current reputation score per empire ID, range [-100, 100]
     */
    reputation?: {
        [key: string]: number;
    };
    /**
     * Decay target per empire ID; reputation moves toward this each cycle
     */
    reputation_baseline?: {
        [key: string]: number;
    };
    /**
     * Hex color
     */
    secondary_color?: string;
    /**
     * Current XP per skill
     */
    skill_xp?: {
        [key: string]: number;
    };
    /**
     * Skill levels keyed by skill ID
     */
    skills?: {
        [key: string]: number;
    };
    stats?: PlayerStats;
    status_message?: string;
    /**
     * ID of wreck currently being towed, empty if not towing
     */
    towing_wreck_id?: string;
    /**
     * Trading, gifting, and exchange access restricted until this time (self-destruct penalty); zero value means no restriction
     */
    trading_restricted_until?: string;
    username: string;
};

